import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { 
    LayoutGrid, 
    Users, 
    Calendar, 
    CheckCircle, 
    LogOut, 
    Search, 
    RefreshCcw, 
    MessageCircle, 
    MapPin, 
    Clock, 
    Shield,
    Phone,
    Smartphone,
    XCircle,
    Navigation,
    Loader2
} from "lucide-react";
import "./Dashboard.css";

const Dashboard = ({ session }) => {
    const [rides, setRides] = useState([]);
    const [searchQuery, setSearchQuery] = useState("");
    const [filter, setFilter] = useState("all");
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchRides();
        const channel = supabase.channel('pahel-hq-v3')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides())
            .subscribe();
        return () => supabase.removeChannel(channel);
    }, []);

    const fetchRides = async () => {
        const { data } = await supabase.from("rides").select("*").order("created_at", { ascending: false });
        if (data) setRides(data);
        setLoading(false);
    };

    const updateStatus = async (id, status) => {
        await supabase.from('rides').update({ status }).eq('id', id);
        fetchRides();
    };

    const handleWhatsApp = (phone, name) => {
        const url = `https://wa.me/91${phone.replace(/\D/g, '')}?text=Hi ${name}, your PAHEL ride booking is confirmed.`;
        window.open(url, '_blank');
    };

    // Calculation logic
    const today = new Date().toISOString().split('T')[0];
    const stats = {
        total: rides.length,
        pending: rides.filter(r => r.status === 'pending').length,
        today: rides.filter(r => r.ride_date === today).length,
        completed: rides.filter(r => r.status === 'completed').length
    };

    const filteredRides = rides.filter(ride => {
        const matchesSearch = ride.passenger_name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                             ride.phone_number.includes(searchQuery);
        const matchesFilter = filter === "all" || ride.status === filter;
        return matchesSearch && matchesFilter;
    });

    if (loading) return (
        <div style={{ display: 'flex', height: '100vh', alignItems: 'center', justifyContent: 'center' }}>
            <Loader2 className="spin" size={40} color="#2563eb" />
        </div>
    );

    return (
        <div className="dashboard-layout">
            <aside className="sidebar">
                <div className="sidebar-logo">
                    <Navigation size={24} fill="#2563eb" color="#2563eb" /> PAHEL ADMIN
                </div>
                <div className="nav-item active"><LayoutGrid size={18} /> Dashboard</div>
                <div className="nav-item"><Users size={18} /> Driver Fleet</div>
                <div className="nav-item"><Calendar size={18} /> Appointments</div>
                <div style={{ marginTop: 'auto' }} className="nav-item" onClick={() => supabase.auth.signOut()}>
                    <LogOut size={18} /> Sign Out
                </div>
            </aside>

            <main className="main-area">
                <header className="header-row" style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '32px' }}>
                    <div>
                        <h2 style={{ margin: 0, fontWeight: 700 }}>Fleet Overview</h2>
                        <span style={{ color: 'var(--text-muted)', fontSize: '14px' }}>System Operator: {session.user.email}</span>
                    </div>
                    <button className="action-btn" onClick={fetchRides}><RefreshCcw size={18} /></button>
                </header>

                <div className="stats-grid">
                    <div className="stat-card">
                        <div className="stat-header">TOTAL BOOKINGS <Users size={14} /></div>
                        <div className="stat-value">{stats.total}</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-header">PENDING APPROVAL <Clock size={14} /></div>
                        <div className="stat-value" style={{ color: 'var(--warning)' }}>{stats.pending}</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-header">TODAY'S DISPATCH <Calendar size={14} /></div>
                        <div className="stat-value" style={{ color: 'var(--primary)' }}>{stats.today}</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-header">COMPLETED <CheckCircle size={14} /></div>
                        <div className="stat-value" style={{ color: 'var(--success)' }}>{stats.completed}</div>
                    </div>
                </div>

                <div className="content-card">
                    <div className="toolbar">
                        <div style={{ display: 'flex', gap: '12px' }}>
                            <div style={{ position: 'relative' }}>
                                <Search size={16} style={{ position: 'absolute', left: '12px', top: '12px', color: '#94a3b8' }} />
                                <input 
                                    type="text" 
                                    placeholder="Search passenger..." 
                                    className="search-input"
                                    style={{ paddingLeft: '36px' }}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                />
                            </div>
                            <select className="search-input" style={{ width: '160px' }} onChange={(e) => setFilter(e.target.value)}>
                                <option value="all">All Statuses</option>
                                <option value="pending">Pending</option>
                                <option value="confirmed">Confirmed</option>
                                <option value="completed">Completed</option>
                                <option value="cancelled">Cancelled</option>
                            </select>
                        </div>
                    </div>

                    <div style={{ overflowX: 'auto' }}>
                        <table className="modern-table">
                            <thead>
                                <tr>
                                    <th>Passenger Info</th>
                                    <th>Route Details</th>
                                    <th>Schedule</th>
                                    <th>Status</th>
                                    <th style={{ textAlign: 'right' }}>Management</th>
                                </tr>
                            </thead>
                            <tbody>
                                {filteredRides.map(ride => (
                                    <tr key={ride.id}>
                                        <td>
                                            <div style={{ fontWeight: '600', color: 'var(--text-main)' }}>{ride.passenger_name}</div>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '12px', color: 'var(--text-muted)', marginTop: '4px' }}>
                                                <Phone size={10} /> {ride.phone_number}
                                            </div>
                                        </td>
                                        <td>
                                            <div style={{ fontSize: '13px', display: 'flex', alignItems: 'center', gap: '6px' }}>
                                                <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: 'var(--success)' }}></div>
                                                {ride.pickup_location}
                                            </div>
                                            <div style={{ fontSize: '13px', display: 'flex', alignItems: 'center', gap: '6px', marginTop: '6px' }}>
                                                <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: 'var(--danger)' }}></div>
                                                {ride.drop_location}
                                            </div>
                                        </td>
                                        <td>
                                            <div style={{ fontWeight: '600', fontSize: '13px' }}>{ride.ride_date}</div>
                                            <div style={{ fontSize: '12px', color: 'var(--text-muted)' }}>{ride.ride_time}</div>
                                        </td>
                                        <td>
                                            <span className={`status-pill status-${ride.status}`}>
                                                {ride.status}
                                            </span>
                                        </td>
                                        <td>
                                            <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
                                                <button className="action-btn" title="WhatsApp Message" onClick={() => handleWhatsApp(ride.phone_number, ride.passenger_name)}>
                                                    <MessageCircle size={16} color="#25D366" />
                                                </button>
                                                <button className="action-btn" title="Confirm Ride" onClick={() => updateStatus(ride.id, 'confirmed')}>
                                                    <Send size={16} color="var(--primary)" />
                                                </button>
                                                <button className="action-btn" title="Mark Completed" onClick={() => updateStatus(ride.id, 'completed')}>
                                                    <CheckCircle size={16} color="var(--success)" />
                                                </button>
                                                <button className="action-btn" title="Cancel Ride" onClick={() => updateStatus(ride.id, 'cancelled')}>
                                                    <XCircle size={16} color="var(--danger)" />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            </main>
        </div>
    );
};

// SVG Fallback for Send icon if not in lucide
const Send = ({ size, color }) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <line x1="22" y1="2" x2="11" y2="13"/><polyline points="22 2 15 22 11 13 2 9 22 2"/>
    </svg>
);

export default Dashboard;
